defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  alias MyApp.{Accounts, Repo}
  alias MyApp.Accounts.User

  def update(conn, %{"id" => id, "user" => user_params}) do
    with {:ok, user} <- Accounts.get_user!(id),
         {:authorized, true} <- check_authorization(conn, user),
         {:ok, updated_user} <- update_user(user, user_params) do
      conn
      |> put_status(:ok)
      |> render("show.json", user: updated_user)
    else
      {:authorized, false} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Forbidden"})
      {:error, changeset} ->
        conn
        |> put_status(:bad_request)
        |> render("error.json", changeset: changeset)
    end
  end

  defp check_authorization(conn, user) do
    current_user = conn.assigns.current_user
    tenant_id = user.tenant_id
    user_role = current_user.role

    case {user_role, tenant_id} do
      {"admin", _} -> {:authorized, true}
      {"manager", ^tenant_id} -> {:authorized, true}
      {"user", ^tenant_id} when current_user.id == user.id -> {:authorized, true}
      _ -> {:authorized, false}
    end
  end

  defp update_user(user, user_params) do
    user
    |> User.changeset(user_params)
    |> validate_fields_access(user_params)
    |> Repo.update()
  end

  defp validate_fields_access(changeset, user_params) do
    current_user = changeset.data

    allowed_fields = 
      case current_user.role do
        "admin" -> Map.keys(user_params)
        "manager" -> [:first_name, :last_name, :email]
        "user" -> [:first_name, :last_name]
      end

    changeset
    |> validate_required(allowed_fields)
    |> cast(user_params, allowed_fields)
  end
end